#include <stdio.h>
#include <limits.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long N, X, Y;
        scanf("%lld %lld %lld", &N, &X, &Y);
        long long best = LLONG_MAX;
        long long maxBuses = (N + 99) / 100; // ceil(N/100)
        for (long long b = 0; b <= maxBuses; ++b) {
            long long remaining = N - b * 100;
            if (remaining < 0) remaining = 0;
            long long c = (remaining + 3) / 4; // ceil(remaining/4)
            long long smoke = b * X + c * Y;
            if (smoke < best) best = smoke;
        }
        printf("%lld\n", best);
    }
    return 0;
}

