#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); X = int(next(it)); Y = int(next(it))
        best = 10**18
        max_b = (N + 99) // 100  # ceil
        for b in range(max_b + 1):
            rem = N - b * 100
            if rem < 0:
                rem = 0
            c = (rem + 3) // 4  # ceil
            smoke = b * X + c * Y
            if smoke < best:
                best = smoke
        out_lines.append(str(best))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

